module div_16bit(
    input [15:0] A, 
    input [7:0] B,
    output reg [15:0] result, 
    output reg [15:0] odd
);
    reg [15:0] a_reg, b_reg;
    integer i;

    always @* begin
        a_reg <= A;
        b_reg <= B;

        for(i = 15; i >= 0; i = i - 1) begin
            if(a_reg[i:i+7] > b_reg) begin
                result[i] <= 1;
                a_reg[i:i+7] <= a_reg[i:i+7] - b_reg;
            end else begin
                result[i] <= 0;
            end

            if(i != 0) begin
                a_reg[i-1:i-8] <= {a_reg[i-1:i-8], a_reg[i]};
            end
        end

        odd <= a_reg;
    end

endmodule
